const item = $input.first().json;
const result = item.chart?.result?.[0]?.meta;

if (!result) {
  return [{ json: { alert: false } }];
}

const currentPrice = result.regularMarketPrice;
const prevClose = result.previousClose;
const changePercent = ((currentPrice - prevClose) / prevClose) * 100;
const absChange = Math.abs(changePercent);

// 只有變動 > 2% 先觸發 alert
if (absChange <= 2) {
  return [{ json: { alert: false } }];
}

const direction = changePercent > 0 ? '📈 上升' : '📉 下跌';

return [{
  json: {
    alert: true,
    ticker: item.ticker,
    name: item.name,
    market: item.market,
    price: currentPrice.toFixed(2),
    changePercent: changePercent.toFixed(2),
    direction: direction,
    prevClose: prevClose.toFixed(2),
    timestamp: new Date().toLocaleString('zh-HK', { timeZone: 'Asia/Hong_Kong' })
  }
}];

const item = $input.first().json;

const message = `🚨 *${item.name} (${item.ticker})* 股價異動

${item.direction} *${item.changePercent}%*

當前價格：$${item.price}
前收市價：$${item.prevClose}
市場：${item.market === 'HK' ? '🇭🇰 港股' : '🇺🇸 美股'}
時間：${item.timestamp}`;

return [{ json: { chatId: '{{ $env.TELEGRAM_CHAT_ID }}', message: message } }];
